class Solution {
public:
    int repeatedStringMatch(string a, string b) {
        string temp = "";
        int count = 0;
        while (temp.length() < b.length()) {
            temp += a;
            count++;
        }
        if (temp.find(b) == string::npos) {
            if (b.length() % a.length() == 0) {
                temp += a;
                if (temp.find(b) == string::npos) return -1;
            } else return -1;
        }
        return count;
    }
};
```
efficiency: HIGH
time complexity: O(b.length())
space complexity: O(b.length())
energy implications: LOW
explanation: We first create a temporary string `temp` by repeating `a` until its length is greater than or equal to `b`. Then, we check if `b` is a substring of `temp`. If not, we check if `b` is a substring of `temp` plus one more repetition of `a`. If still not, we return -1.

